export function getCandidates(constituencyName: string): Candidate[] {
  return CANDIDATES_2024[constituencyName] || [];
}

export function getOpposition(constituencyName: string): Candidate[] {
  return getCandidates(constituencyName).filter(c => !c.elected);
}